const fs = require('fs');
const https = require('https');
const path = require('path');

const outputDir = path.join(__dirname, 'public', 'images');
if (!fs.existsSync(outputDir)) {
    fs.mkdirSync(outputDir, { recursive: true });
}

const generateUrl = (num) => {
    const prompt = `number ${num} in a square frame, futuristic punk aesthetic, cyberpunk style, neon glowing, dark background, digital art, high resolution`;
    return `https://coreva-normal.trae.ai/api/ide/v1/text_to_image?prompt=${encodeURIComponent(prompt)}&image_size=square`;
};

const downloadImage = (num) => {
    const url = generateUrl(num);
    const filePath = path.join(outputDir, `ai-gen-${num}.png`);

    console.log(`Downloading ai-gen-${num}.png...`);

    https.get(url, (res) => {
        // Handle Redirects
        if (res.statusCode === 301 || res.statusCode === 302) {
            console.log(`Redirecting ${num} to ${res.headers.location}`);
            https.get(res.headers.location, (newRes) => {
                if (newRes.statusCode !== 200) {
                     console.error(`Failed to download image ${num} after redirect: Status ${newRes.statusCode}`);
                     newRes.resume();
                     return;
                }
                const stream = fs.createWriteStream(filePath);
                newRes.pipe(stream);
                stream.on('finish', () => {
                    stream.close();
                    console.log(`Saved ai-gen-${num}.png`);
                });
            });
            return;
        }

        if (res.statusCode !== 200) {
            console.error(`Failed to download image ${num}: Status ${res.statusCode}`);
            res.resume();
            return;
        }

        const stream = fs.createWriteStream(filePath);
        res.pipe(stream);

        stream.on('finish', () => {
            stream.close();
            console.log(`Saved ai-gen-${num}.png`);
        });
    }).on('error', (err) => {
        console.error(`Error downloading image ${num}:`, err.message);
    });
};

// Download 1 to 5
for (let i = 1; i <= 5; i++) {
    downloadImage(i);
}

import { NextRequest } from 'next/server';
import { filterPII, ensureSafePrompt, safeMetadata } from '@/lib/safety';
import { generateCaptions, generateAutoSocialCaptions } from '@/lib/contentFactory/text';
import { generateImageForPlatform } from '@/lib/contentFactory/image';
import { validateFactoryRequest, validateFactoryOutput } from '@/lib/contentFactory/validate';
import { addLog, getLogs } from '@/lib/logging';

type Platform = 'linkedin' | 'instagram' | 'twitter';
type Provider = 'mock' | 'dalle' | 'stablediffusion' | 'midjourney';

let generatedStore: Array<{
  platform: Platform;
  text_content: string;
  image_url: string;
  generation_metadata: Record<string, unknown>;
}> = [];

export async function GET() {
  return Response.json({ success: true, items: generatedStore, logs: getLogs() });
}

export async function POST(req: NextRequest) {
  try {
    const t0 = Date.now();
    const body = await req.json();
    addLog({ stage: 'validate_input', input: body });

    const validation = validateFactoryRequest(body);
    if (!validation.valid) {
      addLog({ stage: 'failed', error: { message: 'validation-error', context: { errors: validation.errors } } });
      return Response.json({ success: false, error: 'validation-error', details: validation.errors }, { status: 400 });
    }

    const topic: string = String(body.topic || '');
    const platforms: Platform[] = Array.isArray(body.platforms) && body.platforms.length ? body.platforms : ['linkedin', 'instagram', 'twitter'];
    const provider: Provider = (body.imageProvider || 'mock') as Provider;
    const safetyEnabled: boolean = Boolean(body.safetyEnabled ?? true);
    const autoSocialEnabled: boolean = Boolean(body.autoSocialEnabled ?? false);
    const mode: 'full' | 'image_only' = (body.mode || 'full') as 'full' | 'image_only';

    const safeTopic = safetyEnabled ? ensureSafePrompt(topic) : topic;
    const captions: Partial<Record<Platform, string>> =
      mode === 'image_only'
        ? {}
        : autoSocialEnabled
        ? generateAutoSocialCaptions(safeTopic, platforms)
        : generateCaptions(safeTopic, platforms);

    const results: Array<{
      platform: Platform;
      text_content: string;
      image_url: string;
      generation_metadata: Record<string, unknown>;
    }> = [];

    addLog({ stage: 'processing', input: { topic: safeTopic, platforms, provider, mode } });

    for (const p of platforms) {
      const text = mode === 'image_only'
        ? filterPII(String(body.texts?.[p] || ''))
        : String(captions[p] || '');
      // Basic timeout guard for image generation
      const img = await Promise.race([
        generateImageForPlatform(provider, safeTopic, p),
        new Promise((_, reject) => setTimeout(() => reject(new Error('timeout')), 8000))
      ]) as any;
      const meta = safeMetadata({
        provider,
        platform: p,
        prompt: safeTopic,
        image: img.meta,
        safety: safetyEnabled,
        auto_social_enabled: autoSocialEnabled,
        timestamp: new Date().toISOString(),
      });
      results.push({
        platform: p,
        text_content: text,
        image_url: img.image_url,
        generation_metadata: meta,
      });
    }

    const outValidation = validateFactoryOutput(results);
    if (!outValidation.valid) {
      addLog({ stage: 'failed', error: { message: 'output-validation-error', context: { errors: outValidation.errors } } });
      return Response.json({ success: false, error: 'output-validation-error', details: outValidation.errors }, { status: 500 });
    }

    generatedStore = [...results, ...generatedStore].slice(0, 50);
    const duration = Date.now() - t0;
    addLog({ stage: 'validate_output', output: { items: results }, durationMs: duration });
    addLog({ stage: 'completed', durationMs: duration });
    return Response.json({ success: true, items: results });
  } catch (e: unknown) {
    const err = e as Error;
    addLog({ stage: 'failed', error: { message: err.message || 'content-factory-error', stack: err.stack } });
    return Response.json({ success: false, error: 'content-factory-error' }, { status: 400 });
  }
}

import { NextRequest } from 'next/server';
import { getLogs } from '@/lib/logging';

export const runtime = 'nodejs';

export async function GET(_req: NextRequest) {
  const encoder = new TextEncoder();
  const stream = new ReadableStream({
    start(controller) {
      const write = (data: string) => controller.enqueue(encoder.encode(data));
      write('retry: 3000\n');
      const tick = () => {
        const payload = JSON.stringify({ logs: getLogs().slice(0, 20), ts: Date.now() });
        write(`data: ${payload}\n\n`);
      };
      tick();
      const id = setInterval(tick, 3000);
      const close = () => {
        clearInterval(id);
        controller.close();
      };
      // @ts-expect-error
      controller.oncancel = close;
    },
  });
  return new Response(stream, {
    headers: {
      'content-type': 'text/event-stream',
      'cache-control': 'no-cache',
      connection: 'keep-alive',
    },
  });
}

import { NextRequest } from 'next/server';
import { buildQuery } from '@/lib/search/buildQuery';
import { addLog, getLogs } from '@/lib/logging';

export async function GET() {
  return Response.json({ success: true, logs: getLogs() });
}

export async function POST(req: NextRequest) {
  const t0 = Date.now();
  try {
    const body = await req.json();
    addLog({ stage: 'validate_input', input: { kind: 'search', body } });

    const query = String(body.query || '').trim();
    const exact = Boolean(body.exact ?? false);
    const siteFilters = Array.isArray(body.siteFilters) ? body.siteFilters : [];
    const filetypes = Array.isArray(body.filetypes) ? body.filetypes : [];
    const limit = Math.min(Math.max(Number(body.limit || 5), 1), 10);

    if (!query) {
      addLog({ stage: 'failed', error: { message: 'search-validation-error', context: { reason: 'empty-query' } } });
      return Response.json({ success: false, error: 'search-validation-error' }, { status: 400 });
    }

    const built = buildQuery({ query, exact, siteFilters, filetypes });
    addLog({ stage: 'processing', input: { built, limit } });

    const proxy = process.env.NEXT_PUBLIC_SEARCH_PROXY_URL;
    let results: any[] = [];
    let providerStatus: string | undefined = undefined;
    if (proxy) {
      try {
        const url = `${proxy}?q=${encodeURIComponent(built)}&num=${limit}`;
        const res = await fetch(url, { cache: 'no-store' });
        if (!res.ok) throw new Error(`provider-response-${res.status}`);
        const data = await res.json();
        results = Array.isArray(data.results) ? data.results : (Array.isArray(data.items) ? data.items : []);
        providerStatus = 'ok';
      } catch (e) {
        providerStatus = 'error';
        addLog({ stage: 'failed', error: { message: 'search-provider-error', stack: (e as Error).stack, context: { built, limit } } });
      }
    } else {
      providerStatus = 'missing';
    }

    const duration = Date.now() - t0;
    addLog({ stage: 'validate_output', output: { providerStatus, count: results.length }, durationMs: duration });
    addLog({ stage: 'completed', durationMs: duration });
    return Response.json({ success: true, query: built, results, providerStatus });
  } catch (e) {
    const err = e as Error;
    addLog({ stage: 'failed', error: { message: err.message || 'search-error', stack: err.stack } });
    return Response.json({ success: false, error: 'search-error' }, { status: 400 });
  }
}

'use client';

import { useEffect, useMemo, useState } from 'react';
import { Header } from '@/components/Header';
import { Loader2, AlertCircle, CheckCircle2, Clock } from 'lucide-react';

interface Item {
  platform: 'linkedin' | 'instagram' | 'twitter';
  text_content: string;
  image_url: string;
  generation_metadata: Record<string, unknown>;
}

interface LogEntry {
  id: string;
  timestamp: number;
  stage: string;
  input?: Record<string, unknown>;
  output?: Record<string, unknown>;
  durationMs?: number;
  error?: { message: string; stack?: string; context?: Record<string, unknown> };
}

export default function FactoryDashboardPage() {
  const [items, setItems] = useState<Item[]>([]);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const res = await fetch('/api/content-factory', { cache: 'no-store' });
        const data = await res.json();
        setItems(Array.isArray(data.items) ? data.items : []);
        setLogs(Array.isArray(data.logs) ? data.logs : []);
      } catch (e) {
        setError('Failed to load dashboard data');
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  const parameterKeys = useMemo(() => {
    const setKey = new Set<string>();
    items.forEach(it => {
      Object.keys(it.generation_metadata || {}).forEach(k => setKey.add(k));
    });
    return Array.from(setKey);
  }, [items]);

  return (
    <div className="min-h-screen bg-gray-900 text-white">
      <Header />
      <main className="max-w-6xl mx-auto p-8">
        <div className="flex items-center justify-between mb-8">
          <div>
            <h1 className="text-3xl font-bold">Content Factory Dashboard</h1>
            <p className="text-gray-400">Parameters, status, history, and analytics</p>
          </div>
        </div>

        {loading && (
          <div className="flex items-center justify-center h-64">
            <Loader2 className="h-8 w-8 animate-spin text-primary" />
          </div>
        )}

        {!loading && error && (
          <div className="rounded-xl border border-red-700 bg-red-900/20 p-4 text-red-300 flex items-center gap-2">
            <AlertCircle /> {error}
          </div>
        )}

        {!loading && !error && (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            <section className="rounded-xl border border-gray-700 bg-gray-900 p-4">
              <h2 className="text-xl font-semibold mb-3">Available Parameters</h2>
              <div className="text-sm text-gray-300">
                {parameterKeys.length === 0 && <div className="text-gray-500">No parameters recorded yet</div>}
                {parameterKeys.length > 0 && (
                  <ul className="space-y-2">
                    {parameterKeys.map(k => (
                      <li key={k} className="flex items-center justify-between">
                        <span className="font-mono text-xs">{k}</span>
                        <span className="text-xs text-gray-500">Recorded</span>
                      </li>
                    ))}
                  </ul>
                )}
              </div>
            </section>

            <section className="rounded-xl border border-gray-700 bg-gray-900 p-4">
              <h2 className="text-xl font-semibold mb-3">Generation Status</h2>
              <div className="space-y-3">
                {logs.slice(0, 8).map(l => (
                  <div key={l.id} className="rounded-lg border border-gray-700 p-3">
                    <div className="flex items-center justify-between">
                      <div className="text-sm text-gray-300">Stage: {l.stage}</div>
                      <div className="text-xs text-gray-500">{new Date(l.timestamp).toLocaleTimeString()}</div>
                    </div>
                    <div className="mt-1 text-xs text-gray-400">
                      {typeof l.durationMs === 'number' && (
                        <div className="flex items-center gap-2"><Clock className="w-3 h-3" /> Duration: {l.durationMs} ms</div>
                      )}
                      {l.error && (
                        <div className="mt-1 text-red-400">Error: {l.error.message}</div>
                      )}
                    </div>
                  </div>
                ))}
                {logs.length === 0 && <div className="text-sm text-gray-500">No logs yet</div>}
              </div>
            </section>

            <section className="rounded-xl border border-gray-700 bg-gray-900 p-4">
              <h2 className="text-xl font-semibold mb-3">Latest Items</h2>
              <div className="space-y-4">
                {items.slice(0, 5).map((it, idx) => (
                  <div key={idx} className="rounded-lg border border-gray-700 p-3">
                    <div className="flex items-center justify-between">
                      <div className="text-sm text-gray-300 capitalize">{it.platform}</div>
                      <CheckCircle2 className="w-4 h-4 text-green-500" />
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-3 mt-2">
                      <div className="aspect-video md:aspect-square rounded border border-gray-700 overflow-hidden bg-black/40">
                        <img src={it.image_url} alt="" className="object-contain w-full h-full" />
                      </div>
                      <div className="text-xs whitespace-pre-wrap text-gray-300">{it.text_content}</div>
                    </div>
                  </div>
                ))}
                {items.length === 0 && <div className="text-sm text-gray-500">No generated content yet</div>}
              </div>
            </section>
          </div>
        )}
      </main>
    </div>
  );
}

