              </div>

              <div className="mt-4">
                <div className="flex items-center justify-between mb-2">
                  <div className="text-sm text-gray-300 font-semibold">{monthLabel(calendarYear, calendarMonth)}</div>
                  <div className="flex gap-2">
                    <div className="hidden sm:flex items-center gap-2 mr-4">
                      <button
                        aria-label="Toggle range selection mode"
                        aria-pressed={rangeMode}
                        onClick={() => setRangeMode(v => !v)}
                        className={`px-2 py-1 rounded border text-xs ${rangeMode ? 'border-blue-500 bg-blue-600 text-white' : 'border-gray-700 bg-gray-800 text-gray-200'}`}
                      >
                        {rangeMode ? 'Range Mode: On' : 'Range Mode: Off'}
                      </button>
                    </div>
                    <div className="hidden sm:flex items-center gap-2 mr-4">
                      <label htmlFor="range-start" className="text-xs text-gray-400">Start</label>
                      <input
                        id="range-start"
                        aria-label="Start date"
                        type="date"
                        value={rangeStart ? rangeStart.slice(0,10) : ''}
                        onChange={e => {
                          const iso = e.target.value ? new Date(e.target.value).toISOString() : '';
                          setRangeStart(iso);
                          validateRange(iso, rangeEnd);
                        }}
                        className="bg-gray-900 border border-gray-700 rounded p-1 text-xs"
                      />
                      <label htmlFor="range-end" className="text-xs text-gray-400">End</label>
                      <input
                        id="range-end"
                        aria-label="End date"
                        type="date"
                        value={rangeEnd ? rangeEnd.slice(0,10) : ''}
                        onChange={e => {
                          const iso = e.target.value ? new Date(e.target.value).toISOString() : '';
                          setRangeEnd(iso);
                          validateRange(rangeStart, iso);
                        }}
                        className="bg-gray-900 border border-gray-700 rounded p-1 text-xs"
                      />
                      <button
                        aria-label="Clear date range"
                        className="px-2 py-1 rounded border border-gray-700 bg-gray-800 text-xs"
                        onClick={clearRange}
                      >Clear</button>
                      <button
                        aria-label="Clear selected dates"
                        className="px-2 py-1 rounded border border-gray-700 bg-gray-800 text-xs"
                        onClick={clearSelectedDates}
                      >Clear Dates</button>
                    </div>
                    <button
                      className="px-2 py-1 rounded border border-gray-700 bg-gray-800 text-xs"
                      onClick={() => {
                        const prev = new Date(calendarYear, calendarMonth - 1, 1);
                        setCalendarYear(prev.getFullYear());
                        setCalendarMonth(prev.getMonth());
                      }}
                    >Prev</button>
                    <button
                      className="px-2 py-1 rounded border border-gray-700 bg-gray-800 text-xs"
                      onClick={() => {
                        const next = new Date(calendarYear, calendarMonth + 1, 1);
                        setCalendarYear(next.getFullYear());
                        setCalendarMonth(next.getMonth());
                      }}
                    >Next</button>
                  </div>
                </div>
                <div className="grid grid-cols-7 gap-1 text-xs text-gray-400 mb-1" role="row">
                  <div className="text-center">Sun</div>
                  <div className="text-center">Mon</div>
                  <div className="text-center">Tue</div>
                  <div className="text-center">Wed</div>
                  <div className="text-center">Thu</div>
                  <div className="text-center">Fri</div>
                  <div className="text-center">Sat</div>
                </div>
                <div className="grid grid-cols-7 gap-1" role="grid" aria-label="Calendar">
                  {Array.from({ length: firstDayOfWeek(calendarYear, calendarMonth) }).map((_, i) => (
                    <div key={`empty-${i}`} className={`${styles.calendarDay} border border-gray-800 h-10 rounded bg-gray-900`} role="gridcell" />
                  ))}
                  {Array.from({ length: daysInMonth(calendarYear, calendarMonth) }).map((_, i) => {
                    const day = i + 1;
                    const isSelected = scheduleAt && new Date(scheduleAt).getDate() === day &&
                      new Date(scheduleAt).getMonth() === calendarMonth && new Date(scheduleAt).getFullYear() === calendarYear;
                    const inRange = inSelectedRange(calendarYear, calendarMonth, day);
                    const isStart = isStartDay(calendarYear, calendarMonth, day);
                    const isEnd = isEndDay(calendarYear, calendarMonth, day);
                    const ariaLabel = new Date(calendarYear, calendarMonth, day).toLocaleDateString(undefined, { year: 'numeric', month: 'long', day: 'numeric' });
                    const dateISO = new Date(calendarYear, calendarMonth, day).toISOString();
                    const isSingleSelection = visibleRangeStart && visibleRangeEnd && visibleRangeStart === visibleRangeEnd && isStart;
                    const individuallySelected = isIndividuallySelected(calendarYear, calendarMonth, day);
                    return (
                      <button
                        key={`day-${day}`}
                        onClick={() => {
                          const iso = dateISO;
                          if (rangeMode) {
                            if (!rangeStart) {
                              setRangeStart(iso);
                              setRangeEnd('');
                              setRangeError(null);
                            } else {
                              const a = new Date(rangeStart);
                              const b = new Date(iso);
                              const startISO = (a < b ? a : b).toISOString();
                              const endISO = (a < b ? b : a).toISOString();
                              setRangeStart(startISO);
                              setRangeEnd(endISO);
                              validateRange(startISO, endISO);
                            }
                          } else {
                            toggleIndividualDate(iso);
                          }
                        }}
                        className={`${styles.calendarDay} border h-10 rounded text-sm ${inRange ? styles.calendarDayInRange : 'border-gray-700 bg-gray-800 text-gray-200'} ${individuallySelected ? styles.calendarDayIndividuallySelected : ''} ${isStart ? styles.calendarDayRangeStart : ''} ${isEnd ? styles.calendarDayRangeEnd : ''}`}
                        title={`${day}/${calendarMonth + 1}/${calendarYear}`}
                        role="gridcell"
                        aria-selected={inRange || individuallySelected || isSingleSelection ? true : undefined}
                        aria-label={ariaLabel}
                        id={`calendar-day-${day}`}
                        onKeyDown={e => {
                          const key = e.key;
                          let targetDay = day;
                          if (key === 'ArrowRight') targetDay = day + 1;
                          if (key === 'ArrowLeft') targetDay = day - 1;
                          if (key === 'ArrowUp') targetDay = day - 7;
                          if (key === 'ArrowDown') targetDay = day + 7;
                          if (key === 'Enter' || key === ' ') {
                            const iso = dateISO;
                            if (rangeMode) {
                              if (!rangeStart) {
                                setRangeStart(iso);
                                setRangeEnd('');
                                setRangeError(null);
                              } else {
                                const a = new Date(rangeStart);
                                const b = new Date(iso);
                                const startISO = (a < b ? a : b).toISOString();
                                const endISO = (a < b ? b : a).toISOString();
                                setRangeStart(startISO);
                                setRangeEnd(endISO);
                                validateRange(startISO, endISO);
                              }
                            } else {
                              toggleIndividualDate(iso);
                            }
                          }
                          if (targetDay >= 1 && targetDay <= daysInMonth(calendarYear, calendarMonth)) {
                            const el = document.getElementById(`calendar-day-${targetDay}`);
                            if (el) (el as HTMLElement).focus();
                          }
                        }}
                      >
                        <div className="flex flex-col items-center justify-center h-full">
                          <span>{day}</span>
                        </div>
                      </button>
                    );
                  })}
                </div>
                <div className="mt-2 text-xs text-gray-400">
                  {scheduleAt ? `Scheduled for: ${new Date(scheduleAt).toLocaleString()}` : 'No schedule set'}
                </div>
                <div className="mt-1 text-xs">
                  {rangeError && <span className="text-red-400">{rangeError}</span>}
                  {!rangeError && rangeStart && rangeEnd && (
                    <span className="text-gray-300">
                      Selected: {new Date(rangeStart).toLocaleDateString()} – {new Date(rangeEnd).toLocaleDateString()}
                    </span>
                  )}
                  {!rangeError && selectedDates.length > 0 && (
                    <div className="text-gray-300 mt-1">
                      Dates: {selectedDates.map(d => new Date(d).toLocaleDateString()).join(', ')}
                    </div>
                  )}
                </div>
              </div>

              <button 
                onClick={postContentAction}
                disabled={isPosting}
                className={`w-full py-3 rounded-lg font-bold flex items-center justify-center gap-2 ${isPosting ? 'bg-gray-700 cursor-not-allowed' : 'bg-blue-600 hover:bg-blue-500'}`}
              >
                {isPosting ? 'Broadcasting...' : 'Post to All Channels'}
              </button>

              {postingStatus === 'success' && (
                <div className="mt-3 rounded-lg bg-green-500/20 text-green-300 border border-green-500/30 px-3 py-2 text-sm">
                  Posted successfully
                </div>
              )}
              {postingStatus && postingStatus !== 'success' && (
                <div className="mt-3 rounded-lg bg-red-500/20 text-red-300 border border-red-500/30 px-3 py-2 text-sm">
                  {postingStatus === 'network-error' ? 'Network error while posting' : `Posting failed: ${postingStatus}`}
                </div>
              )}
            </div>

            <div className="mt-8 p-4 bg-gray-900 rounded-lg text-sm text-gray-400">
              <p>Pro Tip: Use the Screenshot Manager service for capturing web assets.</p>
              <a href={`${process.env.NEXT_PUBLIC_SCREENSHOT_URL || 'http://localhost:4010'}/api/screenshots`} target="_blank" className="text-blue-400 hover:underline mt-2 inline-block">
                Open Screenshot Manager
              </a>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
}

'use client';

import { useState } from 'react';
import { Header } from '../../components/Header';
import { Play, CheckCircle, AlertCircle, Phone, ShoppingCart, Truck, CreditCard } from 'lucide-react';

export default function WorkflowTestPage() {
  const [logs, setLogs] = useState<string[]>([]);
  const [isRunning, setIsRunning] = useState(false);
  const [currentStep, setCurrentStep] = useState(0);
  const [testData, setTestData] = useState<any>({});

  const addLog = (msg: string) => {
    const timestamp = new Date().toLocaleTimeString();
    setLogs(prev => [`[${timestamp}] ${msg}`, ...prev]);
  };

  const runTest = async () => {
    setIsRunning(true);
    setLogs([]);
    setCurrentStep(1);
    setTestData({});

    try {
      // 1. Purchase Phase
      addLog('--- PHASE 1: PURCHASE ---');
      addLog('Initiating purchase for Account #ACC-101...');

      const purchaseRes = await fetch('http://localhost:3001/api/accounts/purchase', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ accountId: 'ACC-101', name: 'Premium Account' })
      });

      if (!purchaseRes.ok) throw new Error('Purchase failed');
      const purchaseData = await purchaseRes.json();
      setTestData((prev: any) => ({ ...prev, order: purchaseData.order }));
      addLog(`Purchase Successful! Order ID: ${purchaseData.order.id}`);
      addLog(`Status Verified: ${purchaseData.order.status}`);

      await new Promise(r => setTimeout(r, 1000));
      setCurrentStep(2);

      // 2. Data Entry Phase
      addLog('--- PHASE 2: DATA ENTRY ---');
      const mockShipping = {
        address: '123 Tech Blvd, Silicon Valley, CA',
        phone: '+15550123456',
        email: 'test.user@example.com'
      };
      addLog(`Entering shipping details for ${mockShipping.email}...`);

      const shippingRes = await fetch('http://localhost:3001/api/shipping/update', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ orderId: purchaseData.order.id, shipping: mockShipping })
      });

      if (!shippingRes.ok) throw new Error('Shipping update failed');
      const shippingData = await shippingRes.json();
      addLog('Shipping details saved successfully.');

      await new Promise(r => setTimeout(r, 1000));
      setCurrentStep(3);

      // 3. Cart Integration
      addLog('--- PHASE 3: CART INTEGRATION ---');
      addLog('Adding purchased account to cart for processing...');

      const cartRes = await fetch('http://localhost:3001/api/cart/add', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ item: { id: purchaseData.order.accountId, name: purchaseData.order.name, price: 49.99 } })
      });

      if (!cartRes.ok) throw new Error('Cart add failed');
      const cartData = await cartRes.json();
      addLog(`Cart Updated. Total Items: ${cartData.cart.items.length}`);

      await new Promise(r => setTimeout(r, 1000));
      setCurrentStep(4);

      // 4. Call Bot Activation
      addLog('--- PHASE 4: CALL BOT ACTIVATION ---');
      addLog('Triggering AI Voice Agent...');

      const callRes = await fetch('http://localhost:3001/api/support/call', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ phoneNumber: mockShipping.phone, reason: 'Post-Purchase Verification' })
      });

      if (!callRes.ok) throw new Error('Call trigger failed');
      const callData = await callRes.json();
      addLog(`Call Initiated! Call ID: ${callData.callId}`);
      addLog(`Call Status: ${callData.status}`);

      setCurrentStep(5);
      addLog('--- TEST COMPLETE: SUCCESS ---');

    } catch (e: any) {
      addLog(`[ERROR] ${e.message}`);
      console.error(e);
    } finally {
      setIsRunning(false);
    }
  };

  return (
    <div className="min-h-screen bg-gray-900 text-white">
      <Header />
      <main className="max-w-4xl mx-auto p-8">
        <div className="flex justify-between items-center mb-8">
          <div>
            <h1 className="text-3xl font-bold">Purchase-to-Call Workflow Test</h1>
            <p className="text-gray-400">Live verification of the end-to-end sales and support cycle.</p>
          </div>
          <button 
            onClick={runTest}
            disabled={isRunning}
            className={`flex items-center gap-2 px-6 py-3 rounded-lg font-bold transition-all ${
              isRunning ? 'bg-gray-700 cursor-wait' : 'bg-green-600 hover:bg-green-500 shadow-lg shadow-green-900/20'
            }`}
          >
            {isRunning ? <div className="animate-spin rounded-full h-5 w-5 border-2 border-white border-t-transparent" /> : <Play className="w-5 h-5" />}
            {isRunning ? 'Running Test...' : 'Start Live Test'}
          </button>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Status Steps */}
          <div className="space-y-4">
            <StepCard 
              step={1} 
              current={currentStep} 
              title="Purchase Account" 
              icon={<CreditCard className="w-5 h-5" />} 
              desc="Simulate buying Account #ACC-101"
            />
            <StepCard 
              step={2} 
              current={currentStep} 
              title="Data Entry" 
              icon={<Truck className="w-5 h-5" />} 
              desc="Input shipping & contact info"
            />
            <StepCard 
              step={3} 
              current={currentStep} 
              title="Cart Integration" 
              icon={<ShoppingCart className="w-5 h-5" />} 
              desc="Sync order to shopping cart"
            />
            <StepCard 
              step={4} 
              current={currentStep} 
              title="Call Activation" 
              icon={<Phone className="w-5 h-5" />} 
              desc="Trigger AI verification call"
            />
            <StepCard 
              step={5} 
              current={currentStep} 
              title="Verification" 
              icon={<CheckCircle className="w-5 h-5" />} 
              desc="Confirm data persistence"
            />
          </div>

          {/* Logs Console */}
          <div className="lg:col-span-2 bg-black rounded-xl border border-gray-800 p-4 font-mono text-sm h-[500px] overflow-y-auto shadow-inner">
            {logs.length === 0 && (
              <div className="text-gray-600 text-center mt-20">
                Click "Start Live Test" to begin...
              </div>
            )}
            {logs.map((log, i) => (
              <div key={i} className={`mb-2 ${log.includes('ERROR') ? 'text-red-400' : log.includes('PHASE') ? 'text-blue-400 font-bold mt-4' : 'text-green-300'}`}>
                {log}
              </div>
            ))}
          </div>
        </div>
      </main>
    </div>
  );
}

function StepCard({ step, current, title, icon, desc }: any) {
  const status = current > step ? 'completed' : current === step ? 'active' : 'pending';

  return (
    <div className={`p-4 rounded-lg border transition-all ${
      status === 'active' ? 'bg-gray-800 border-blue-500 shadow-blue-900/20 shadow-md' : 
      status === 'completed' ? 'bg-gray-800/50 border-green-900 opacity-70' : 
      'bg-gray-900 border-gray-800 opacity-50'
    }`}>
      <div className="flex items-center gap-3 mb-1">
        <div className={`p-2 rounded-full ${
          status === 'active' ? 'bg-blue-900 text-blue-200' : 
          status === 'completed' ? 'bg-green-900 text-green-200' : 
          'bg-gray-800 text-gray-500'
        }`}>
          {status === 'completed' ? <CheckCircle className="w-4 h-4" /> : icon}
        </div>
        <h3 className={`font-bold ${status === 'active' ? 'text-white' : 'text-gray-400'}`}>{title}</h3>
      </div>
      <p className="text-xs text-gray-500 ml-11">{desc}</p>
    </div>
  );
}

'use client';

import React, { useState, useEffect, useRef } from 'react';
import { Device, Call } from '@twilio/voice-sdk';
import { Phone, PhoneOff, Mic, MicOff, User, History, Activity, BookUser, Plus, Save } from 'lucide-react';

interface CallAgentProps {
  identity?: string;
}

export function CallAgent({ identity = 'support-agent-1' }: CallAgentProps) {
  const [device, setDevice] = useState<Device | null>(null);
  const [connection, setConnection] = useState<Call | null>(null);
  const [status, setStatus] = useState<string>('Offline');
  const [number, setNumber] = useState('');
  const [isMuted, setIsMuted] = useState(false);
  const [logs, setLogs] = useState<any[]>([]);
  const [token, setToken] = useState<string | null>(null);
  const [contacts, setContacts] = useState<any[]>([]);
  const [activeTab, setActiveTab] = useState<'history' | 'contacts'>('history');
  const [contactName, setContactName] = useState('');
  const [contactPhone, setContactPhone] = useState('');
  const [isSaving, setIsSaving] = useState(false);

  // Initialize Twilio Device
  useEffect(() => {
    const initDevice = async () => {
      try {
        setStatus('Initializing...');
        // Fetch capability token from backend
        const res = await fetch('http://localhost:3001/api/voice/token', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ identity })
        });

        const contentType = res.headers.get('content-type');
        if (!contentType || !contentType.includes('application/json')) {
             throw new Error('Invalid server response (not JSON)');
        }

        const data = await res.json();

        if (data.token === 'mock-token-for-testing') {
            setToken('mock');
            setStatus('Ready (Mock Mode)');
            return;
        }

        const newDevice = new Device(data.token, {
            logLevel: 1,
            // codecPreferences: ['opus', 'pcmu'], // Removed to avoid TS strict type issues
        });

        newDevice.on('ready', () => setStatus('Ready'));
        newDevice.on('error', (error) => {
            console.error('Device Error:', error);
            setStatus(`Error: ${error.message}`);
        });
        newDevice.on('connect', (conn) => {
            setConnection(conn);
            setStatus('In Call');
        });
        newDevice.on('disconnect', () => {
            setConnection(null);
            setStatus('Ready');
        });
        newDevice.on('incoming', (conn) => {
            setConnection(conn);
            setStatus('Incoming Call...');
            // Auto answer for demo purposes or show accept UI
            // conn.accept(); 
        });

        await newDevice.register();
        setDevice(newDevice);
      } catch (e) {
        console.error(e);
        setStatus('Initialization Failed');
      }
    };

    initDevice();

    // Cleanup
    return () => {
      if (device) device.destroy();
    };
  }, [identity]);

  // Fetch logs periodically
  useEffect(() => {
      // Initial contacts fetch
      fetch('http://localhost:3001/api/agent/contacts')
        .then(res => res.json())
        .then(data => setContacts(data.contacts || []))
        .catch(console.error);

      const interval = setInterval(() => {
          fetch('http://localhost:3001/api/voice/logs')
            .then(res => res.json())
            .then(data => setLogs(data.logs || []))
            .catch(e => console.error(e));
      }, 5000);
      return () => clearInterval(interval);
  }, []);

  const saveContact = async () => {
      if (!contactPhone || !contactName) return;

      // Basic validation
      if (!/^\+?[1-9]\d{1,14}$/.test(contactPhone)) {
          alert('Invalid phone format');
          return;
      }

      setIsSaving(true);
      try {
          const res = await fetch('http://localhost:3001/api/agent/contacts', {
              method: 'POST',
              headers: {'Content-Type': 'application/json'},
              body: JSON.stringify({ name: contactName, phone: contactPhone })
          });

          const contentType = res.headers.get('content-type');
          if (!contentType || !contentType.includes('application/json')) {
               throw new Error('Server error: Invalid response');
          }

          const data = await res.json();
          if (data.success) {
              setContacts(data.contacts);
              setContactName('');
              setContactPhone('');
          } else {
              console.error(data.error);
              alert(data.error);
          }
      } catch (e) {
          console.error(e);
      } finally {
          setIsSaving(false);
      }
  };

  const handleCall = async () => {
    if (!number) return;

    if (token === 'mock') {
        setStatus('Calling (Mock)...');
        // Use new dedicated /api/call endpoint
        try {
            const res = await fetch('http://localhost:3001/api/call', {
                method: 'POST',
                headers: { 
                    'Content-Type': 'application/json',
                    'Accept': 'application/json' 
                },
                body: JSON.stringify({ phone: number })
            });

            if (!res.ok) {
                const err = await res.json().catch(() => ({ message: 'Unknown error' }));
                throw new Error(err.message || 'Call failed');
            }

            const data = await res.json();
            console.log('Call Initiated:', data);
            setStatus('In Call (Mock)');
        } catch (e: any) {
            console.error('Call Error:', e);
            setStatus(`Error: ${e.message}`);
        }
        return;
    }

    if (device) {
      try {
        const conn = await device.connect({ params: { To: number } });
        setConnection(conn);
      } catch (e: any) {
        setStatus(`Call Failed: ${e.message}`);
      }
    }
  };

  const handleHangup = () => {
    if (token === 'mock') {
        setStatus('Ready (Mock Mode)');
        setConnection(null);
        return;
    }
    if (connection) {
      connection.disconnect();
    }
  };

  const toggleMute = () => {
    if (connection) {
      const newState = !isMuted;
      connection.mute(newState);
      setIsMuted(newState);
    } else if (token === 'mock') {
        setIsMuted(!isMuted);
    }
  };

  return (
    <div className="bg-gray-900 border border-gray-700 rounded-xl overflow-hidden shadow-2xl w-full max-w-md mx-auto">
      {/* Header */}
      <div className="bg-gray-800 p-4 border-b border-gray-700 flex justify-between items-center">
        <div className="flex items-center gap-2">
          <div className={`w-3 h-3 rounded-full ${status.includes('Ready') || status.includes('In Call') ? 'bg-green-500' : 'bg-red-500'}`}></div>
          <span className="font-bold text-white">Agent Panel</span>
        </div>
        <div className="text-xs text-gray-400 bg-black/30 px-2 py-1 rounded">
          {status}
        </div>
      </div>

      {/* Dialer */}
      <div className="p-6">
        <div className="mb-6">
          <input 
            type="tel" 
            placeholder="+1 (555) 000-0000"
            className="w-full bg-black/20 border border-gray-600 rounded-lg p-4 text-2xl text-center text-white tracking-wider focus:border-blue-500 focus:outline-none"
            value={number}
            onChange={e => setNumber(e.target.value)}
          />
        </div>

        <div className="grid grid-cols-3 gap-4 mb-6">
          {[1,2,3,4,5,6,7,8,9,'*',0,'#'].map(n => (
            <button 
              key={n}
              onClick={() => setNumber(prev => prev + n)}
              className="bg-gray-800 hover:bg-gray-700 text-white py-3 rounded-lg text-xl font-bold transition-colors"
            >
              {n}
            </button>
          ))}
        </div>

        {/* Controls */}
        <div className="flex justify-center gap-6">
          <button 
            onClick={toggleMute}
            className={`p-4 rounded-full ${isMuted ? 'bg-yellow-600 text-black' : 'bg-gray-700 text-white hover:bg-gray-600'}`}
          >
            {isMuted ? <MicOff /> : <Mic />}
          </button>

          {(status.includes('In Call') || status.includes('Calling')) ? (
            <button 
              onClick={handleHangup}
              className="p-4 rounded-full bg-red-600 text-white hover:bg-red-500 shadow-lg shadow-red-500/30"
            >
              <PhoneOff className="w-8 h-8" />
            </button>
          ) : (
            <button 
              onClick={handleCall}
              className="p-4 rounded-full bg-green-600 text-white hover:bg-green-500 shadow-lg shadow-green-500/30"
            >
              <Phone className="w-8 h-8" />
            </button>
          )}
        </div>
      </div>

      {/* Recent Activity / Contacts */}
      <div className="bg-gray-800/50 p-0 border-t border-gray-700">
        <div className="flex border-b border-gray-700">
            <button 
                onClick={() => setActiveTab('history')}
                className={`flex-1 p-3 text-xs font-bold uppercase flex items-center justify-center gap-2 ${activeTab === 'history' ? 'bg-gray-800 text-white' : 'text-gray-500 hover:text-gray-300'}`}
            >
                <History className="w-3 h-3" /> Recent Calls
            </button>
            <button 
                onClick={() => setActiveTab('contacts')}
                className={`flex-1 p-3 text-xs font-bold uppercase flex items-center justify-center gap-2 ${activeTab === 'contacts' ? 'bg-gray-800 text-white' : 'text-gray-500 hover:text-gray-300'}`}
            >
                <BookUser className="w-3 h-3" /> Contacts
            </button>
        </div>

        <div className="max-h-48 overflow-y-auto p-4">
          {activeTab === 'history' ? (
            <div className="space-y-2">
              {logs.slice().reverse().map((log: any, i) => (
                <div key={i} className="flex justify-between items-center text-sm p-2 hover:bg-white/5 rounded">
                  <div className="flex items-center gap-2">
                    <span className={`w-1.5 h-1.5 rounded-full ${log.status === 'completed' ? 'bg-green-500' : 'bg-yellow-500'}`}></span>
                    <span className="text-gray-300">{log.to || 'Unknown'}</span>
                  </div>
                  <span className="text-gray-500 text-xs">
                    {log.status} {log.duration ? `(${log.duration}s)` : ''}
                  </span>
                </div>
              ))}
              {logs.length === 0 && <p className="text-gray-500 text-center py-2">No logs yet</p>}
            </div>
          ) : (
            <div className="space-y-4">
                {/* Add Contact Form */}
                <div className="bg-black/20 p-3 rounded-lg space-y-3">
                    <h4 className="text-xs font-bold text-gray-400 uppercase">Add New Contact</h4>
                    <div className="space-y-2">
                        <div>
                            <label className="block text-[10px] text-gray-500 mb-1">Name</label>
                            <input 
                                className="w-full bg-black/40 border border-gray-600 rounded px-2 py-1.5 text-sm text-white focus:outline-none focus:border-blue-500" 
                                placeholder="Enter name" 
                                value={contactName}
                                onChange={e => setContactName(e.target.value)}
                            />
                        </div>
                        <div>
                            <label className="block text-[10px] text-gray-500 mb-1">Phone Number</label>
                            <input 
                                type="tel"
                                className="w-full bg-black/40 border border-gray-600 rounded px-2 py-1.5 text-sm text-white focus:outline-none focus:border-blue-500" 
                                placeholder="+1234567890" 
                                value={contactPhone}
                                onChange={e => setContactPhone(e.target.value)}
                            />
                        </div>
                        <button 
                            onClick={saveContact}
                            disabled={!contactPhone || !contactName || isSaving}
                            className="w-full bg-blue-600 hover:bg-blue-500 disabled:opacity-50 disabled:cursor-not-allowed text-white py-2 rounded text-xs font-bold flex items-center justify-center transition-all"
                        >
                            {isSaving ? 'Saving...' : <><Save className="w-3 h-3 mr-1" /> Save Contact</>}
                        </button>
                    </div>
                </div>

                {/* List */}
                <div className="space-y-1 mt-2">
                    {contacts.map((c: any) => (
                        <div key={c.id} className="flex justify-between items-center bg-black/20 p-2 rounded hover:bg-black/40 cursor-pointer group" onClick={() => setNumber(c.phone)}>
                            <span className="text-sm text-white font-medium">{c.name}</span>
                            <span className="text-xs text-gray-400 group-hover:text-white transition-colors">{c.phone}</span>
                        </div>
                    ))}
                    {contacts.length === 0 && <p className="text-gray-500 text-center text-xs py-2">No contacts saved</p>}
                </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

