'use client';

import React, { useEffect, useState } from 'react';
import { CatalogItem } from './CatalogItem';
import { Filter, Search, Loader2 } from 'lucide-react';
import { useLiveStatus } from '@/context/LiveStatusContext';
import { LiveBadge } from './LiveBadge';

interface Post {
  id: string;
  content: string;
  metadata?: {
    mediaUrl?: string;
    [key: string]: unknown;
  };
  ipfsHash?: string;
  timestamp?: string;
  date?: string;
}

interface CatalogGridProps {
  initialPosts: Post[];
}

export function CatalogGrid({ initialPosts }: CatalogGridProps) {
  const [posts, setPosts] = useState<Post[]>(initialPosts);
  const { latestPost } = useLiveStatus();

  // Filter States
  const [searchQuery, setSearchQuery] = useState('');
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [activeFilters, setActiveFilters] = useState({
    sort: 'newest' as 'newest' | 'oldest',
    type: 'all' as 'all' | 'image' | 'text'
  });
  const filterRef = React.useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (latestPost) {
      setPosts(prev => {
        if (prev.find(p => p.id === latestPost.id)) return prev;
        return [latestPost, ...prev];
      });
    }
  }, [latestPost]);

  // Handle click outside to close dropdown
  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (filterRef.current && !filterRef.current.contains(event.target as Node)) {
        setIsFilterOpen(false);
      }
    }
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Filter Logic
  const filteredPosts = React.useMemo(() => {
    const q = searchQuery.trim().toLowerCase();
    const tokens = q.length ? q.split(/\s+/).filter(Boolean) : [];
    function textFor(post: Post) {
      const t = [
        post.content || '',
        post.metadata?.title?.toString() || '',
        post.metadata?.description?.toString() || ''
      ].join(' ').toLowerCase();
      return t;
    }
    function score(post: Post) {
      const t = textFor(post);
      if (!q) return 0;
      let s = 0;
      if (t.includes(q)) s += 5;
      for (const token of tokens) {
        if (t.includes(token)) s += 3;
      }
      if (tokens.includes('robot')) {
        const robotHints = ['robot','android','mech','cyborg','bot'];
        if (robotHints.some(h => t.includes(h))) s += 2;
      }
      return s;
    }
    let arr = posts.map(p => ({ post: p, score: score(p) }))
      .filter(({ post, score }) => {
        const t = textFor(post);
        const matches = q ? (t.includes(q) || tokens.some(tok => t.includes(tok))) : true;
        if (!matches) return false;
        if (activeFilters.type === 'image' && !post.metadata?.mediaUrl) return false;
        if (activeFilters.type === 'text' && post.metadata?.mediaUrl) return false;
        return true;
      });
    arr.sort((a, b) => {
      if (b.score !== a.score) return b.score - a.score;
      const dateA = new Date(a.post.timestamp || a.post.date || 0).getTime();
      const dateB = new Date(b.post.timestamp || b.post.date || 0).getTime();
      return activeFilters.sort === 'newest' ? dateB - dateA : dateA - dateB;
    });
    if (tokens.includes('robot')) {
      const top = arr.slice(0, 3).map(x => x.post);
      const hasRobotToken = top.some(p => {
        const t = textFor(p);
        return t.includes('robot') || t.includes('android') || t.includes('mech') || t.includes('cyborg') || t.includes('bot');
      });
      if (!hasRobotToken) {
        arr = arr.filter(({ post }) => {
          const t = textFor(post);
          return t.includes('robot') || t.includes('android') || t.includes('mech') || t.includes('cyborg') || t.includes('bot');
        });
      }
    }
    return arr.map(x => x.post);
  }, [posts, searchQuery, activeFilters]);

  const activeFilterCount = (activeFilters.sort !== 'newest' ? 1 : 0) + (activeFilters.type !== 'all' ? 1 : 0);

  return (
    <main className="container mx-auto px-4 py-8">
      {/* Controls */}
      <div className="mb-8 flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
        <div className="flex items-center gap-2">
          <h1 className="text-3xl font-bold text-white">Latest Drops</h1>
          <div className="md:hidden">
            <LiveBadge />
          </div>
        </div>

        <div className="flex items-center gap-3 z-20">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-zinc-500" />
            <input 
              type="text" 
              placeholder="Search assets..." 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="h-10 w-full rounded-lg border border-zinc-800 bg-zinc-900 pl-9 pr-4 text-sm text-white placeholder:text-zinc-500 focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary sm:w-64"
            />
          </div>

          <div className="relative" ref={filterRef}>
            <button 
              onClick={() => setIsFilterOpen(!isFilterOpen)}
              className={`flex h-10 items-center gap-2 rounded-lg border px-4 text-sm font-medium transition-colors ${isFilterOpen || activeFilterCount > 0 ? 'border-primary bg-primary/10 text-primary' : 'border-zinc-800 bg-zinc-900 text-white hover:bg-zinc-800'}`}
              aria-expanded={isFilterOpen}
              aria-haspopup="true"
            >
              <Filter className="h-4 w-4" />
              Filter
              {activeFilterCount > 0 && (
                <span className="ml-1 flex h-5 w-5 items-center justify-center rounded-full bg-primary text-[10px] text-white">
                  {activeFilterCount}
                </span>
              )}
            </button>

            {/* Dropdown Menu */}
            {isFilterOpen && (
              <div className="absolute right-0 top-12 w-56 rounded-xl border border-zinc-800 bg-zinc-900 shadow-xl p-4 animate-in fade-in zoom-in-95 duration-200 z-50">
                <div className="space-y-4">
                  <div>
                    <h3 className="text-xs font-semibold text-zinc-500 uppercase tracking-wider mb-2">Sort By</h3>
                    <div className="space-y-1">
                      <label className="flex items-center gap-2 text-sm text-zinc-300 cursor-pointer hover:text-white">
                        <input 
                          type="radio" 
                          name="sort" 
                          checked={activeFilters.sort === 'newest'}
                          onChange={() => setActiveFilters(prev => ({ ...prev, sort: 'newest' }))}
                          className="accent-primary"
                        />
                        Newest First
                      </label>
                      <label className="flex items-center gap-2 text-sm text-zinc-300 cursor-pointer hover:text-white">
                        <input 
                          type="radio" 
                          name="sort" 
                          checked={activeFilters.sort === 'oldest'}
                          onChange={() => setActiveFilters(prev => ({ ...prev, sort: 'oldest' }))}
                          className="accent-primary"
                        />
                        Oldest First
                      </label>
                    </div>
                  </div>

                  <div className="h-px bg-zinc-800" />

                  <div>
                    <h3 className="text-xs font-semibold text-zinc-500 uppercase tracking-wider mb-2">Asset Type</h3>
                    <div className="space-y-1">
                      <label className="flex items-center gap-2 text-sm text-zinc-300 cursor-pointer hover:text-white">
                        <input 
                          type="radio" 
                          name="type" 
                          checked={activeFilters.type === 'all'}
                          onChange={() => setActiveFilters(prev => ({ ...prev, type: 'all' }))}
                          className="accent-primary"
                        />
                        All Assets
                      </label>
                      <label className="flex items-center gap-2 text-sm text-zinc-300 cursor-pointer hover:text-white">
                        <input 
                          type="radio" 
                          name="type" 
                          checked={activeFilters.type === 'image'}
                          onChange={() => setActiveFilters(prev => ({ ...prev, type: 'image' }))}
                          className="accent-primary"
                        />
                        Images Only
                      </label>
                      <label className="flex items-center gap-2 text-sm text-zinc-300 cursor-pointer hover:text-white">
                        <input 
                          type="radio" 
                          name="type" 
                          checked={activeFilters.type === 'text'}
                          onChange={() => setActiveFilters(prev => ({ ...prev, type: 'text' }))}
                          className="accent-primary"
                        />
                        Text Only
                      </label>
                    </div>
                  </div>

                  <button 
                    onClick={() => {
                      setActiveFilters({ sort: 'newest', type: 'all' });
                      setSearchQuery('');
                      setIsFilterOpen(false);
                    }}
                    className="w-full rounded bg-zinc-800 py-2 text-xs font-medium text-zinc-400 hover:bg-zinc-700 hover:text-white transition-colors"
                  >
                    Reset Filters
                  </button>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Grid */}
      <div className="grid grid-cols-1 gap-6 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4">
        {filteredPosts.map((post, index) => (
          <CatalogItem
            key={post.id || `post-${index}`}
            id={post.id || `post-${index}`}
            content={post.content}
            mediaUrl={post.metadata?.mediaUrl}
            ipfsHash={post.ipfsHash}
            timestamp={post.timestamp || post.date || new Date().toISOString()}
            metadata={post.metadata}
          />
        ))}
      </div>

      {filteredPosts.length === 0 && (
        <div className="flex h-64 flex-col items-center justify-center rounded-2xl border border-dashed border-zinc-800 bg-zinc-900/30">
          <Loader2 className="mb-2 h-8 w-8 animate-spin text-zinc-500" />
          <p className="text-zinc-400">
            {posts.length === 0 ? "Loading catalog..." : "No assets found matching your filters."}
          </p>
          {posts.length > 0 && (
             <button 
               onClick={() => { setSearchQuery(''); setActiveFilters({ sort: 'newest', type: 'all' }); }}
               className="mt-4 text-sm text-primary hover:underline"
             >
               Clear all filters
             </button>
          )}
        </div>
      )}
    </main>
  );
}

import React, { useState } from 'react';
import Image from 'next/image';
import { format } from 'date-fns';
import { ShoppingCart, Coins, ShieldCheck, AlertTriangle } from 'lucide-react';
import { cn } from '@/lib/utils';
import { motion } from 'framer-motion';
import { useCart } from '@/context/CartContext';
import { toast } from 'sonner';

export interface CatalogItemProps {
  id: string;
  content: string;
  mediaUrl?: string | null;
  ipfsHash?: string | null;
  timestamp: string;
  metadata?: {
    title?: string;
    [key: string]: unknown;
  };
  priceUsd?: number;
}

export function CatalogItem({ 
  id,
  content, 
  mediaUrl, 
  ipfsHash, 
  timestamp, 
  metadata,
  priceUsd = ((): number => {
    const m = metadata as { priceUsd?: number } | undefined;
    return typeof m?.priceUsd === 'number' ? m!.priceUsd! : 49.99;
  })()
}: CatalogItemProps) {
  const fcPrice = (priceUsd * 10).toFixed(0); // Mock conversion 1 USD = 10 FC
  const { addToCart } = useCart();

  // Handle image URL
  const getImageUrl = (url?: string | null) => {
    if (!url) return '/placeholder-future-city.svg';
    if (url.startsWith('http')) return url;
    if (url.startsWith('Qm') || url.startsWith('bafy')) return `https://ipfs.io/ipfs/${url}`;
    return `http://localhost:3001${url.startsWith('/') ? '' : '/'}${url}`;
  };

  const [imgSrc, setImgSrc] = React.useState(getImageUrl(mediaUrl));
  const [isLoading, setIsLoading] = React.useState(true);
  const [hasError, setHasError] = useState(false);
  const [isFallback, setIsFallback] = useState(false);

  React.useEffect(() => {
    setImgSrc(getImageUrl(mediaUrl));
    setIsLoading(true);
    setHasError(false);
  }, [mediaUrl]);

  // Truncate content
  const safeContent = content || '';
  const description = safeContent.length > 200 
    ? safeContent.substring(0, 200) + '...' 
    : safeContent;

  const [isPurchasing, setIsPurchasing] = React.useState(false);

  const handlePurchase = async (currency: 'usd' | 'fc') => {
    setIsPurchasing(true);
    try {
      await addToCart({ 
        id, 
        title: metadata?.title || 'Digital Asset', 
        price: priceUsd,
        quantity: 1,
        currency,
        imageUrl: hasError ? undefined : imgSrc,
        description: safeContent,
        imageError: hasError,
        originalPrompt: String(metadata?.prompt ?? metadata?.title ?? 'Unknown Prompt'),
        originalFilename: mediaUrl || 'Unknown File',
        metadata: {
          ...metadata,
          imageError: hasError,
          originalPrompt: metadata?.prompt || metadata?.title || 'Unknown Prompt'
        }
      });
      toast.success(`Added to cart! (${currency.toUpperCase()})`);

    } catch (e) {
      console.error('Purchase error:', e);
      toast.error('Failed to add to cart.');
    } finally {
      setIsPurchasing(false);
    }
  };

  return (
    <motion.div 
      initial={{ opacity: 0, y: 20 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true }}
      whileHover={{ scale: 1.02, translateY: -5 }}
      transition={{ duration: 0.3 }}
      className="group relative flex flex-col overflow-hidden rounded-xl border border-zinc-800 bg-zinc-900/50 shadow-lg hover:shadow-2xl hover:shadow-primary/20 transition-all duration-300"
    >
      {/* Image Section */}
      <div className="relative aspect-[4/3] w-full overflow-hidden bg-zinc-950">
        {isLoading && (
          <div className="absolute inset-0 animate-pulse bg-zinc-800" />
        )}

        {!hasError ? (
          <Image
            src={imgSrc}
            alt="Item thumbnail"
            fill
            className={cn(
              "object-cover transition-transform duration-500 group-hover:scale-110",
              isLoading ? "opacity-0" : "opacity-100"
            )}
            sizes="(max-width: 768px) 100vw, (max-width: 1200px) 50vw, 33vw"
            onLoad={() => setIsLoading(false)}
            onError={() => {
              setHasError(true);
              setIsLoading(false);
              // Log error to backend
              fetch('http://localhost:3001/api/log/error', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                  type: 'IMAGE_LOAD_FAILURE',
                  message: `Failed to load image for item ${id}`,
                  details: { mediaUrl, filename: mediaUrl, prompt: metadata?.prompt || metadata?.title }
                })
              }).catch(console.error);
            }}
          />
        ) : (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-zinc-900 p-4 text-center">
            <AlertTriangle className="mb-2 h-8 w-8 text-amber-500" />
            <p className="text-xs font-medium text-zinc-400 mb-1">Image Unavailable</p>
            <p className="text-[10px] text-zinc-600 font-mono break-all line-clamp-2">
              Prompt: {String(metadata?.prompt ?? metadata?.title ?? 'Unknown')}
            </p>
            <p className="text-[10px] text-zinc-700 font-mono break-all mt-1">
              File: {mediaUrl}
            </p>
          </div>
        )}
        <div className="absolute top-3 right-3">
          <span className="inline-flex items-center rounded-full bg-black/60 px-3 py-1 text-xs font-medium text-white backdrop-blur-md border border-white/10">
            {(() => {
              try {
                const date = new Date(timestamp);
                return !isNaN(date.getTime()) ? format(date, 'MMM d, yyyy') : 'Recent';
              } catch {
                return 'Recent';
              }
            })()}
          </span>
        </div>
        {ipfsHash && (
          <div className="absolute bottom-3 left-3">
            <span className="inline-flex items-center rounded-full bg-blue-500/20 px-2 py-1 text-xs font-medium text-blue-200 backdrop-blur-md border border-blue-500/30">
              <ShieldCheck className="mr-1 h-3 w-3" />
              IPFS Verified
            </span>
          </div>
        )}
      </div>

      {/* Content Section */}
      <div className="flex flex-1 flex-col p-5">
        <div className="mb-4">
          <h3 className="mb-2 text-xl font-bold text-white line-clamp-1">
            {metadata?.title || 'Exclusive Digital Asset'}
          </h3>
          <p className="text-sm text-zinc-400 line-clamp-3">
            {description}
          </p>
        </div>

        {/* Pricing */}
        <div className="mt-auto space-y-4">
          <div className="flex items-end justify-between border-t border-zinc-800 pt-4">
            <div>
              <p className="text-xs text-zinc-500 uppercase tracking-wider">Price</p>
              <div className="flex items-baseline gap-2">
                <span className="text-2xl font-bold text-white">${priceUsd.toFixed(2)}</span>
                <span className="text-sm text-zinc-500">USD</span>
              </div>
            </div>
            <div className="text-right">
              <p className="text-xs text-amber-500 uppercase tracking-wider">FC Price</p>
              <div className="flex items-baseline gap-1 justify-end">
                <Coins className="h-4 w-4 text-amber-400" />
                <span className="text-xl font-bold text-amber-400">{fcPrice}</span>
                <span className="text-xs text-amber-500">FC</span>
              </div>
            </div>
          </div>

          {/* Actions */}
          <div className="grid grid-cols-2 gap-3">
            <button 
              onClick={() => handlePurchase('usd')}
              disabled={isPurchasing}
              className="flex items-center justify-center gap-2 rounded-lg bg-white px-4 py-2.5 text-sm font-semibold text-black transition-colors hover:bg-zinc-200 disabled:opacity-50 disabled:cursor-not-allowed"
              data-testid="buy-usd"
            >
              {isPurchasing ? <div className="h-4 w-4 animate-spin rounded-full border-2 border-black border-t-transparent" /> : <ShoppingCart className="h-4 w-4" />}
              Buy Crypto
            </button>
            <button 
              onClick={() => handlePurchase('fc')}
              disabled={isPurchasing}
              className="flex items-center justify-center gap-2 rounded-lg bg-amber-500 px-4 py-2.5 text-sm font-semibold text-black transition-colors hover:bg-amber-400 disabled:opacity-50 disabled:cursor-not-allowed"
              data-testid="buy-fc"
            >
              {isPurchasing ? <div className="h-4 w-4 animate-spin rounded-full border-2 border-black border-t-transparent" /> : <Coins className="h-4 w-4" />}
              Buy w/ FC
            </button>
          </div>
        </div>
      </div>
    </motion.div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import Image from 'next/image';
import { ShoppingCart, Shirt, Coffee, ArrowRight } from 'lucide-react';
import { cn } from '@/lib/utils';

interface Product {
  id: string;
  name: string;
  description: string;
  basePrice: number;
  currency: string;
  variants: string[];
  colors: string[];
  image: string;
}

export function ProductCustomizer({ initialImageUrl }: { initialImageUrl: string | null }) {
  const [products, setProducts] = useState<Product[]>([]);
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [selectedVariant, setSelectedVariant] = useState<string>('');
  const [selectedColor, setSelectedColor] = useState<string>('');
  const [loading, setLoading] = useState(true);
  const [orderStatus, setOrderStatus] = useState<'idle' | 'processing' | 'success' | 'error'>('idle');

  useEffect(() => {
    fetch('http://localhost:3001/api/products')
      .then(res => res.json())
      .then(data => {
        if (data.success) {
          setProducts(data.products);
          if (data.products.length > 0) {
            setSelectedProduct(data.products[0]);
            setSelectedVariant(data.products[0].variants[0]);
            setSelectedColor(data.products[0].colors[0]);
          }
        }
      })
      .catch(err => console.error(err))
      .finally(() => setLoading(false));
  }, []);

  const handleOrder = async () => {
    if (!selectedProduct) return;
    setOrderStatus('processing');
    try {
        const res = await fetch('http://localhost:3001/api/orders', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                items: [{
                    productId: selectedProduct.id,
                    variant: selectedVariant,
                    color: selectedColor,
                    customImage: initialImageUrl,
                    quantity: 1,
                    price: selectedProduct.basePrice
                }],
                shippingAddress: {
                    name: "Test User",
                    line1: "123 Tech Lane",
                    city: "San Francisco",
                    country: "US"
                },
                totalAmount: selectedProduct.basePrice
            })
        });
        const data = await res.json();
        if (data.success) {
            setOrderStatus('success');
        } else {
            setOrderStatus('error');
        }
    } catch (e) {
        setOrderStatus('error');
    }
  };

  if (loading) return <div className="animate-pulse h-96 bg-zinc-900 rounded-xl"></div>;

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
      {/* Preview Area */}
      <div className="relative aspect-square bg-zinc-900 rounded-2xl overflow-hidden border border-zinc-800 flex items-center justify-center">
         {/* Product Base Layer */}
         <div className="absolute inset-0 flex items-center justify-center opacity-50">
             {selectedProduct?.id.includes('mug') ? <Coffee size={300} className="text-zinc-700" /> : <Shirt size={400} className="text-zinc-700" />}
         </div>

         {/* AI Image Overlay */}
         {initialImageUrl && (
             <div className="relative w-1/2 h-1/2 shadow-2xl mix-blend-overlay opacity-90">
                 <Image 
                    src={initialImageUrl} 
                    alt="Design" 
                    fill 
                    className="object-contain" 
                    unoptimized={initialImageUrl.startsWith('http://localhost')}
                 />
             </div>
         )}

         <div className="absolute bottom-4 right-4 bg-black/80 px-4 py-2 rounded-full text-xs text-white backdrop-blur">
             Preview Mode
         </div>
      </div>

      {/* Controls */}
      <div className="space-y-8">
        <div>
            <h1 className="text-3xl font-bold mb-2">Customize Your Gear</h1>
            <p className="text-zinc-400">Apply your generated artwork to premium products.</p>
        </div>

        <div className="space-y-4">
            <label className="text-sm font-medium text-zinc-300">Select Product</label>
            <div className="grid grid-cols-2 gap-4">
                {products.map(p => (
                    <button
                        key={p.id}
                        onClick={() => { setSelectedProduct(p); setSelectedVariant(p.variants[0]); setSelectedColor(p.colors[0]); }}
                        className={cn(
                            "p-4 rounded-xl border text-left transition-all",
                            selectedProduct?.id === p.id 
                                ? "border-primary bg-primary/10 ring-1 ring-primary" 
                                : "border-zinc-800 bg-zinc-900/50 hover:border-zinc-700"
                        )}
                    >
                        <div className="font-semibold">{p.name}</div>
                        <div className="text-sm text-zinc-400">${p.basePrice}</div>
                    </button>
                ))}
            </div>
        </div>

        {selectedProduct && (
            <div className="space-y-6">
                <div>
                    <label className="text-sm font-medium text-zinc-300 mb-3 block">Size / Variant</label>
                    <div className="flex flex-wrap gap-2">
                        {selectedProduct.variants.map(v => (
                            <button
                                key={v}
                                onClick={() => setSelectedVariant(v)}
                                className={cn(
                                    "px-4 py-2 rounded-lg text-sm font-medium border transition-all",
                                    selectedVariant === v
                                        ? "border-white bg-white text-black"
                                        : "border-zinc-800 bg-zinc-900 text-zinc-400 hover:border-zinc-700"
                                )}
                            >
                                {v}
                            </button>
                        ))}
                    </div>
                </div>

                <div>
                    <label className="text-sm font-medium text-zinc-300 mb-3 block">Color</label>
                    <div className="flex flex-wrap gap-2">
                        {selectedProduct.colors.map(c => (
                            <button
                                key={c}
                                onClick={() => setSelectedColor(c)}
                                className={cn(
                                    "px-4 py-2 rounded-lg text-sm font-medium border transition-all",
                                    selectedColor === c
                                        ? "border-white bg-white text-black"
                                        : "border-zinc-800 bg-zinc-900 text-zinc-400 hover:border-zinc-700"
                                )}
                            >
                                {c}
                            </button>
                        ))}
                    </div>
                </div>
            </div>
        )}

        <div className="pt-6 border-t border-zinc-800">
            <div className="flex items-center justify-between mb-6">
                <div className="text-zinc-400">Total</div>
                <div className="text-2xl font-bold">${selectedProduct?.basePrice.toFixed(2)}</div>
            </div>

            <button 
                onClick={handleOrder}
                disabled={orderStatus === 'processing' || orderStatus === 'success'}
                className={cn(
                    "w-full py-4 rounded-xl font-bold text-lg flex items-center justify-center gap-2 transition-all",
                    orderStatus === 'success' 
                        ? "bg-green-500 text-white" 
                        : "bg-white text-black hover:bg-zinc-200"
                )}
            >
                {orderStatus === 'processing' && <div className="animate-spin rounded-full h-5 w-5 border-b-2 border-black"></div>}
                {orderStatus === 'success' ? 'Order Placed!' : 'Add to Cart & Checkout'}
                {orderStatus === 'idle' && <ArrowRight className="w-5 h-5" />}
            </button>
            {orderStatus === 'success' && (
                <p className="text-green-500 text-center mt-2 text-sm">
                    Order confirmed! Check your email for tracking.
                </p>
            )}
        </div>
      </div>
    </div>
  );
}

